# System Verification Script for Crystal AI Stack
import sys, os, importlib, traceback, json, time, textwrap
from types import ModuleType

BASE_DIR = "/mnt/data"
if BASE_DIR not in sys.path:
    sys.path.insert(0, BASE_DIR)

modules_to_check = [
    "unified_crystal_engine",
    "revolutionary_crystal_runtime",
    "layer5_autonomous_voice",           # mobile voice; may have optional deps
    "layer3_cluster_b",
    "layer2_recursive_self_awareness",
    "layer2_unified_dual_process",
    "ghost_relic_system",
    "emotional_depth_mod",
    "dimensional_scoring_orchestrator",
    "dimensional_integration",           # uploaded as dimensional_integration.py
]

report = {
    "timestamp": time.strftime("%Y-%m-%d %H:%M:%S UTC", time.gmtime()),
    "base_dir": BASE_DIR,
    "imports": {},
    "smoke_tests": {},
    "static_findings": {},
    "summary": {},
}

def safe_import(name):
    try:
        m = importlib.import_module(name)
        report["imports"][name] = {"status":"ok"}
        return m
    except Exception as e:
        tb = traceback.format_exc()
        report["imports"][name] = {"status":"error", "error": str(e), "traceback": tb}
        return None

# 1) Import pass
mods = {name: safe_import(name) for name in modules_to_check}

# 2) Static checks for common pitfalls
def grep_file(fname, needle_list):
    path = os.path.join(BASE_DIR, f"{fname}.py")
    findings = {}
    try:
        with open(path, "r", encoding="utf-8") as f:
            src = f.read()
        for needle in needle_list:
            idxs = [i for i in range(len(src)) if src.find(needle, i) == i]
            # simple count
            findings[needle] = len(idxs)
        return findings
    except Exception as e:
        return {"_error": str(e)}

needles = [
    "create_crystal", "evolve_crystal", "ensure_crystal",
    "Layer3ClusterA", "internal_alignment_runtime",
    "layer4_emotional_crystal_runtime", "integration_hooks",
    "UnifiedCrystalAI", "UnifiedCrystalMemory", "UnifiedCrystal",
    "CrystalLevel", "FacetPathwayNavigator",
]

static = {}
for fn in ["unified_crystal_engine","revolutionary_crystal_runtime","layer5_autonomous_voice",
           "layer3_cluster_b","layer2_recursive_self_awareness","layer2_unified_dual_process",
           "ghost_relic_system","emotional_depth_mod","dimensional_scoring_orchestrator",
           "dimensional_integration"]:
    static[fn] = grep_file(fn, needles)

report["static_findings"] = static

# 3) Smoke tests
def smoke_unified_crystal_engine(mod):
    res = {"status":"skipped"}
    try:
        # create system
        create = getattr(mod, "create_unified_crystal_system", None)
        if not callable(create):
            return {"status":"error","error":"create_unified_crystal_system not found"}
        ai = create(os.path.join(BASE_DIR, "crystal_system_memory.json"))
        
        # check memory and ensure_crystal
        memory = getattr(ai, "memory", None)
        if memory is None:
            return {"status":"error","error":"ai.memory missing"}
        
        ensure = getattr(memory, "ensure_crystal", None)
        if not callable(ensure):
            return {"status":"error","error":"memory.ensure_crystal not found"}
        
        cid = ensure("TestConcept", content="A test concept.", context="verification")
        get_by_concept = getattr(memory, "get_crystal_by_concept", None)
        crit = getattr(memory, "get_crystal", None)
        crystal_obj = None
        if callable(get_by_concept):
            crystal_obj = get_by_concept("TestConcept")
        elif callable(crit):
            crystal_obj = crit(cid)
        
        # access a facet
        got_definition = None
        if crystal_obj is not None:
            get_fc = getattr(crystal_obj, "get_facet_content", None)
            if callable(get_fc):
                got_definition = get_fc("definition")
        
        res = {
            "status":"ok",
            "created_crystal_id": cid,
            "definition": got_definition,
            "has_FacetPathwayNavigator": hasattr(mod, "FacetPathwayNavigator"),
        }
        return res
    except Exception as e:
        return {"status":"error","error":str(e),"traceback":traceback.format_exc()}

def smoke_runtime(mod_runtime, mod_engine):
    res = {"status":"skipped"}
    try:
        # Instantiate foundational objects if available flags evaluate from module namespace
        res_flags = {}
        for flag in [
            "FOUNDATION_AVAILABLE","ORCHESTRATOR_AVAILABLE","GHOST_RELIC_AVAILABLE",
            "CONVERSATIONAL_AVAILABLE","EMOTIONAL_INTEGRATION_AVAILABLE",
            "CLUSTER_A_AVAILABLE","DIMENSIONAL_INTEGRATION_AVAILABLE"
        ]:
            res_flags[flag] = getattr(mod_runtime, flag, None)
        
        res["flags"] = res_flags
        # Build an engine to simulate minimal operations
        if mod_engine is not None:
            create = getattr(mod_engine, "create_unified_crystal_system", None)
            ai = create(os.path.join(BASE_DIR, "crystal_system_memory.json"))
            # create a couple concepts
            cid1 = ai.memory.ensure_crystal("River", content="Flowing water body")
            cid2 = ai.memory.ensure_crystal("Mountain", content="Large elevated landform")
            # link if method present
            link = getattr(ai.memory, "link_crystals", None)
            if callable(link):
                link(cid1, cid2, weight=1.7)
            res["engine_smoke"] = {"ok": True, "concepts": ["River","Mountain"]}
        else:
            res["engine_smoke"] = {"ok": False, "reason":"engine module None"}
        res["status"]="ok"
        return res
    except Exception as e:
        return {"status":"error","error":str(e),"traceback":traceback.format_exc()}

def smoke_layer3(mod_l3, mod_engine):
    res = {"status":"skipped"}
    try:
        if mod_l3 is None or mod_engine is None:
            return {"status":"error","error":"missing modules"}
        create = getattr(mod_engine, "create_unified_crystal_system", None)
        ai = create(os.path.join(BASE_DIR, "crystal_system_memory.json"))
        # Seed a concept with a definition facet
        cid = ai.memory.ensure_crystal("Guitar", content="A stringed instrument played with fingers or pick")
        crystal = ai.memory.get_crystal_by_concept("Guitar")
        # Build synthesis engine and attempt synthesis
        BasicSynthesisEngine = getattr(mod_l3, "BasicSynthesisEngine", None)
        if BasicSynthesisEngine is None:
            return {"status":"error","error":"BasicSynthesisEngine not found"}
        synth = BasicSynthesisEngine(ai)
        res_synth = synth.synthesize_knowledge([crystal], query_context="test")
        # Extract insight text
        insight_text = getattr(res_synth, "primary_insight", None)
        if insight_text:
            insight_text = insight_text.insight_text
        res = {"status":"ok","insight":insight_text}
        return res
    except Exception as e:
        return {"status":"error","error":str(e),"traceback":traceback.format_exc()}

