report["smoke_tests"]["unified_crystal_engine"] = smoke_unified_crystal_engine(mods["unified_crystal_engine"])
report["smoke_tests"]["revolutionary_crystal_runtime"] = smoke_runtime(mods["revolutionary_crystal_runtime"], mods["unified_crystal_engine"])
report["smoke_tests"]["layer3_cluster_b"] = smoke_layer3(mods["layer3_cluster_b"], mods["unified_crystal_engine"])

