Here’s the upgraded static-analysis script. It adds a second pass to look across all modules, so if one file defines a function and another imports or calls it, that will be counted as “used.”  

```python
# full_coverage_trace.py
import os, ast, json
from pathlib import Path

def collect_defs_calls(path):
    """Return sets of all definitions and calls/imports in a file."""
    with open(path, "r", encoding="utf8") as f:
        tree = ast.parse(f.read(), filename=path)

    defined = set()
    called = set()
    for node in ast.walk(tree):
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)):
            defined.add(node.name)
        elif isinstance(node, ast.Call):
            if isinstance(node.func, ast.Name):
                called.add(node.func.id)
            elif isinstance(node.func, ast.Attribute):
                called.add(node.func.attr)
        elif isinstance(node, (ast.Import, ast.ImportFrom)):
            for n in node.names:
                called.add(n.name.split(".")[0])
    return defined, called

def run_analysis(base_dir):
    files = list(Path(base_dir).glob("*.py"))
    defs, calls = {}, {}

    # Pass 1: collect definitions and calls per file
    for p in files:
        defined, called = collect_defs_calls(p)
        defs[p.name] = defined
        calls[p.name] = called

    # Pass 2: merge call sets across files
    global_calls = set().union(*calls.values())

    # Pass 3: build report
    report = {}
    for fname, defined in defs.items():
        unused = sorted(defined - global_calls)
        report[fname] = {
            "total_defined": len(defined),
            "unused_count": len(unused),
            "unused": unused
        }

    print(json.dumps(report, indent=2))

if __name__ == "__main__":
    run_analysis(os.path.dirname(__file__))
```

